    77→/// Merges imported groups for this module's workflow.
    78→fn merge_imported_groups(current: &[Group], imported: &[Group]) -> Vec<Group> {
    79→    let mut merged = current.to_vec();
    80→    let mut index_by_group_path: HashMap<String, usize> = HashMap::new();
    81→    for (index, group) in merged.iter().enumerate() {
    82→        index_by_group_path.insert(group.id.clone(), index);
    83→    }
    84→
    85→    for imported_group in imported {
    86→        if let Some(index) = index_by_group_path.get(&imported_group.id).copied() {
    87→            merged[index] = merge_group_by_provider_name(&merged[index], imported_group);
    88→            continue;
    89→        }
    90→        let normalized = normalize_group_provider_ids(imported_group.clone());
    91→        index_by_group_path.insert(normalized.id.clone(), merged.len());
    92→        merged.push(normalized);
    93→    }
    94→
    95→    merged
    96→}
    97→
    98→/// Merges group by provider name for this module's workflow.
    99→fn merge_group_by_provider_name(current: &Group, imported: &Group) -> Group {
   100→    let mut providers = current.providers.clone();
   101→    let mut current_index_by_name: HashMap<String, usize> = HashMap::new();
   102→    for (index, provider) in providers.iter().enumerate() {
   103→        current_index_by_name
   104→            .entry(provider_name_key(&provider.name))
   105→            .or_insert(index);
   106→    }
   107→
   108→    let mut used_provider_ids: HashSet<String> = providers
   109→        .iter()
   110→        .filter_map(|provider| {
   111→            let id = provider.id.trim();
   112→            if id.is_empty() {
   113→                None
   114→            } else {
   115→                Some(id.to_string())
   116→            }
   117→        })
   118→        .collect();
   119→
   120→    let imported_active_name = imported
   121→        .active_provider_id
   122→        .as_ref()
   123→        .and_then(|active_id| {
   124→            imported
   125→                .providers
   126→                .iter()
   127→                .find(|provider| provider.id == *active_id)
   128→        })
   129→        .map(|provider| provider.name.clone());
   130→
   131→    for imported_provider in &imported.providers {
   132→        let name_key = provider_name_key(&imported_provider.name);
   133→        if let Some(index) = current_index_by_name.get(&name_key).copied() {
   134→            let mut next_provider = imported_provider.clone();
   135→            next_provider.id = providers[index].id.clone();
   136→            providers[index] = next_provider;
   137→            continue;
   138→        }
   139→
   140→        let mut next_provider = imported_provider.clone();
   141→        next_provider.id = alloc_provider_id(&imported_provider.id, &mut used_provider_ids);
   142→        current_index_by_name.insert(name_key, providers.len());
   143→        providers.push(next_provider);
   144→    }
   145→
   146→    let mut next_active_provider_id = current.active_provider_id.clone();
   147→    if let Some(active_name) = imported_active_name {
   148→        if let Some(provider) = providers
   149→            .iter()
   150→            .find(|provider| provider.name == active_name)
   151→        {
   152→            next_active_provider_id = Some(provider.id.clone());
   153→        }
   154→    }
   155→    if let Some(active_id) = next_active_provider_id.clone() {
   156→        let exists = providers.iter().any(|provider| provider.id == active_id);
   157→        if !exists {
   158→            next_active_provider_id = None;
   159→        }
   160→    }
   161→
   162→    Group {
   163→        id: current.id.clone(),
   164→        name: imported.name.clone(),
   165→        models: imported.models.clone(),
   166→        active_provider_id: next_active_provider_id,
   167→        providers,
   168→    }
   169→}
