   171→/// Normalizes group provider IDs for this module's workflow.
   172→fn normalize_group_provider_ids(mut group: Group) -> Group {
   173→    let mut used_ids = HashSet::new();
   174→    let mut old_to_new_id: HashMap<String, String> = HashMap::new();
   175→    for provider in &mut group.providers {
   176→        let old_id = provider.id.clone();
   177→        let new_id = alloc_provider_id(&provider.id, &mut used_ids);
   178→        provider.id = new_id.clone();
   179→        if !old_id.trim().is_empty() {
   180→            old_to_new_id.insert(old_id, new_id);
   181→        }
   182→    }
   183→
   184→    if let Some(active_id) = group.active_provider_id.clone() {
   185→        if let Some(next_active_id) = old_to_new_id.get(&active_id) {
   186→            group.active_provider_id = Some(next_active_id.clone());
   187→        } else {
   188→            let exists = group
   189→                .providers
   190→                .iter()
   191→                .any(|provider| provider.id == active_id);
   192→            if !exists {
   193→                group.active_provider_id = None;
   194→            }
   195→        }
   196→    }
   197→
   198→    group
   199→}
   200→
   201→/// Performs alloc provider ID.
   202→fn alloc_provider_id(candidate: &str, used_ids: &mut HashSet<String>) -> String {
   203→    let candidate = candidate.trim();
   204→    if !candidate.is_empty() && !used_ids.contains(candidate) {
   205→        used_ids.insert(candidate.to_string());
   206→        return candidate.to_string();
   207→    }
   208→    loop {
   209→        let id = Uuid::new_v4().to_string();
   210→        if used_ids.insert(id.clone()) {
   211→            return id;
   212→        }
   213→    }
   214→}
   215→
   216→/// Performs provider name key.
   217→fn provider_name_key(name: &str) -> String {
   218→    name.trim().to_lowercase()
   219→}
