   140→/// Build outbound request headers for the selected upstream protocol.
   141→///
   142→/// - Anthropic uses `x-api-key` + `Anthropic-version`.
   143→/// - OpenAI surfaces use standard `Authorization: Bearer ...`.
   144→pub(super) fn build_rule_headers(protocol: &RuleProtocol, rule: &Rule) -> HashMap<String, String> {
   145→    let mut headers = HashMap::new();
   146→    headers.insert("content-type".to_string(), "application/json".to_string());
   147→    match protocol {
   148→        RuleProtocol::Anthropic => {
   149→            headers.insert("x-api-key".to_string(), rule.token.clone());
   150→            headers.insert("anthropic-version".to_string(), "2023-06-01".to_string());
   151→        }
   152→        RuleProtocol::Openai | RuleProtocol::OpenaiCompletion => {
   153→            headers.insert(
   154→                "authorization".to_string(),
   155→                format!("Bearer {}", rule.token),
   156→            );
   157→        }
   158→    }
   159→    headers
   160→}
