   162→/// Refresh in-memory route index when config revision changes.
   163→///
   164→/// This keeps hot-path routing lock-free from full config traversal while still
   165→/// reacting to runtime config updates.
   166→pub(super) fn refresh_route_index_if_needed(state: &ServiceState) -> Result<(), String> {
   167→    let observed_revision = state.config_revision.load(Ordering::Acquire);
   168→    let cached_revision = state.route_index_revision.load(Ordering::Acquire);
   169→    if observed_revision == cached_revision {
   170→        return Ok(());
   171→    }
   172→
   173→    let next_index = state
   174→        .config
   175→        .read()
   176→        .map_err(|_| "config lock poisoned".to_string())
   177→        .map(|cfg| build_route_index(&cfg))?;
   178→
   179→    let mut guard = state
   180→        .route_index
   181→        .write()
   182→        .map_err(|_| "route index lock poisoned".to_string())?;
   183→    *guard = next_index;
   184→    state
   185→        .route_index_revision
   186→        .store(observed_revision, Ordering::Release);
   187→
   188→    Ok(())
   189→}
