   191→/// Build a fast lookup table `group_id -> active route resolution`.
   192→///
   193→/// The index carries three states so request handling can distinguish:
   194→/// - group exists with ready active provider,
   195→/// - group exists but no active provider configured,
   196→/// - group exists but active_provider_id points to a missing provider.
   197→pub(super) fn build_route_index(config: &ProxyConfig) -> RouteIndex {
   198→    let mut index = HashMap::with_capacity(config.groups.len());
   199→    for group in &config.groups {
   200→        let resolution = match group.active_provider_id.as_ref() {
   201→            Some(active_rule_id) => {
   202→                match group
   203→                    .providers
   204→                    .iter()
   205→                    .find(|rule| rule.id == *active_rule_id)
   206→                {
   207→                    Some(rule) => RouteResolution::Ready(ActiveRoute {
   208→                        group_name: group.name.clone(),
   209→                        group_models: group.models.clone(),
   210→                        rule: rule.clone(),
   211→                    }),
   212→                    None => RouteResolution::MissingActiveRule {
   213→                        group_name: group.name.clone(),
   214→                        active_rule_id: active_rule_id.clone(),
   215→                    },
   216→                }
   217→            }
   218→            None => RouteResolution::NoActiveRule {
   219→                group_name: group.name.clone(),
   220→            },
   221→        };
   222→        index.insert(group.id.clone(), resolution);
   223→    }
   224→    index
   225→}
