   227→/// Validate required active-rule fields before forwarding traffic.
   228→pub(super) fn assert_rule_ready(rule: &Rule) -> Result<(), (u16, String)> {
   229→    if rule.name.trim().is_empty() {
   230→        return Err((409, "Active rule name is empty".into()));
   231→    }
   232→    if rule.default_model.trim().is_empty() {
   233→        return Err((409, "Active rule defaultModel is empty".into()));
   234→    }
   235→    if rule.token.trim().is_empty() {
   236→        return Err((409, "Active rule token is empty".into()));
   237→    }
   238→    if rule.api_address.trim().is_empty() {
   239→        return Err((409, "Active rule apiAddress is empty".into()));
   240→    }
   241→    Ok(())
   242→}
