   244→/// Resolve forwarded model name using request model, group allow-list, and rule mappings.
   245→///
   246→/// Resolution order:
   247→/// 1. requested model if present and allowed by group model list,
   248→/// 2. exact/normalized rule model mapping,
   249→/// 3. rule default model.
   250→pub(super) fn resolve_target_model(
   251→    rule: &Rule,
   252→    group_models: &[String],
   253→    request_body: &Value,
   254→) -> String {
   255→    let requested = request_body
   256→        .get("model")
   257→        .and_then(|v| v.as_str())
   258→        .map(|s| s.trim().to_string())
   259→        .filter(|s| !s.is_empty());
   260→
   261→    if let Some(model) = requested {
   262→        if let Some(matched_model) = find_group_model_match(group_models, &model) {
   263→            return rule
   264→                .model_mappings
   265→                .get(&model)
   266→                .cloned()
   267→                .or_else(|| rule.model_mappings.get(matched_model).cloned())
   268→                .unwrap_or(model);
   269→        }
   270→    }
   271→
   272→    rule.default_model.clone()
   273→}
   274→
   275→/// Finds the best matching group model pattern for a requested model string.
   276→fn find_group_model_match<'a>(group_models: &'a [String], requested: &str) -> Option<&'a str> {
   277→    let mut best: Option<&str> = None;
   278→    for model in group_models {
   279→        let candidate = model.trim();
   280→        if candidate.is_empty() {
   281→            continue;
   282→        }
   283→        if !is_model_match(candidate, requested) {
   284→            continue;
   285→        }
   286→        if best
   287→            .map(|curr| candidate.len() > curr.len())
   288→            .unwrap_or(true)
   289→        {
   290→            best = Some(candidate);
   291→        }
   292→    }
   293→    best
   294→}
   295→
   296→/// Returns whether model match is true.
   297→fn is_model_match(candidate: &str, requested: &str) -> bool {
   298→    if candidate == requested {
   299→        return true;
   300→    }
   301→
   302→    if let Some(prefix) = candidate.strip_suffix('*') {
   303→        return !prefix.is_empty() && requested.starts_with(prefix);
   304→    }
   305→
   306→    requested.starts_with(candidate) && requested.as_bytes().get(candidate.len()) == Some(&b'-')
   307→}
