    33→/// Returns whether the state has server setting changed.
    34→fn has_server_setting_changed(prev: &ProxyConfig, next: &ProxyConfig) -> bool {
    35→    prev.server.host != next.server.host
    36→        || prev.server.port != next.server.port
    37→        || prev.server.auth_enabled != next.server.auth_enabled
    38→        || prev.server.local_bearer_token != next.server.local_bearer_token
    39→}
    40→
    41→/// Performs sync runtime config.
    42→pub async fn sync_runtime_config(
    43→    state: &SharedState,
    44→    prev: ProxyConfig,
    45→    next: ProxyConfig,
    46→) -> Result<(bool, ProxyStatus), String> {
    47→    let mut restarted = false;
    48→    let status_before = state.runtime.get_status();
    49→    if status_before.running && has_server_setting_changed(&prev, &next) {
    50→        state.runtime.stop().await?;
    51→        state.runtime.start().await?;
    52→        restarted = true;
    53→    }
    54→
    55→    Ok((restarted, state.runtime.get_status()))
    56→}
