    64→impl ProxyRuntime {
    65→    /// Construct proxy runtime with shared config/stores and prebuilt route index.
    66→    pub fn new(
    67→        config: Arc<RwLock<ProxyConfig>>,
    68→        config_revision: Arc<AtomicU64>,
    69→        log_store: LogStore,
    70→        stats_store: StatsStore,
    71→    ) -> Result<Self, String> {
    72→        let initial_route_index = config
    73→            .read()
    74→            .map_err(|_| "config lock poisoned".to_string())
    75→            .map(|cfg| routing::build_route_index(&cfg))?;
    76→        let client = Client::builder()
    77→            .connect_timeout(std::time::Duration::from_millis(
    78→                UPSTREAM_CONNECT_TIMEOUT_MS,
    79→            ))
    80→            .build()
    81→            .map_err(|e| format!("create http client failed: {e}"))?;
    82→
    83→        Ok(Self {
    84→            inner: Arc::new(ProxyRuntimeInner {
    85→                config,
    86→                config_revision: config_revision.clone(),
    87→                route_index: Arc::new(RwLock::new(initial_route_index)),
    88→                route_index_revision: Arc::new(AtomicU64::new(
    89→                    config_revision.load(Ordering::Acquire),
    90→                )),
    91→                log_store,
    92→                stats_store,
    93→                metrics: Arc::new(observability::MetricsState::new()),
    94→                server: Mutex::new(None),
    95→                client,
    96→            }),
    97→        })
    98→    }
    99→
   100→    /// Start Axum proxy server if not already running.
   101→    pub async fn start(&self) -> Result<ProxyStatus, String> {
   102→        if self.is_running() {
   103→            return Ok(self.get_status());
   104→        }
   105→
   106→        let config = self
   107→            .inner
   108→            .config
   109→            .read()
   110→            .map_err(|_| "config lock poisoned".to_string())?
   111→            .clone();
   112→
   113→        let (listener, bound_host) =
   114→            net::bind_proxy_listener(&config.server.host, config.server.port).await?;
   115→
   116→        // Initialize transformer registry (simplified for ccNexus architecture)
   117→        let transformer_registry = Arc::new(crate::transformer::registry::TransformerRegistry::new());
   118→
   119→        let (tx, rx) = oneshot::channel();
   120→        let service_state = ServiceState {
   121→            config: self.inner.config.clone(),
   122→            config_revision: self.inner.config_revision.clone(),
   123→            route_index: self.inner.route_index.clone(),
   124→            route_index_revision: self.inner.route_index_revision.clone(),
   125→            log_store: self.inner.log_store.clone(),
   126→            stats_store: self.inner.stats_store.clone(),
   127→            metrics: self.inner.metrics.clone(),
   128→            client: self.inner.client.clone(),
   129→            transformer_registry,
   130→        };
   131→
   132→        let app = Router::new()
   133→            .route("/healthz", get(pipeline::healthz))
   134→            .route("/metrics-lite", get(pipeline::metrics_lite))
   135→            .route("/oc/:group_id", post(pipeline::handle_proxy_root))
   136→            .route("/oc/:group_id/*suffix", post(pipeline::handle_proxy_suffix))
   137→            .with_state(service_state);
   138→
   139→        self.inner.metrics.mark_started();
   140→
   141→        let handle = tokio::spawn(async move {
   142→            let server = axum::serve(listener, app);
   143→            let graceful = server.with_graceful_shutdown(async {
   144→                let _ = rx.await;
   145→            });
   146→            let _ = graceful.await;
   147→        });
   148→
   149→        let address = format!(
   150→            "http://{}:{}",
   151→            net::public_host_for_status(&bound_host),
   152→            config.server.port
   153→        );
   154→        let lan_address = match bound_host.as_str() {
   155→            "0.0.0.0" | "::" => {
   156→                net::detect_local_ipv4().map(|ip| format!("http://{}:{}", ip, config.server.port))
   157→            }
   158→            _ => None,
   159→        };
   160→        let running = RunningServer {
   161→            address,
   162→            lan_address,
   163→            shutdown: Some(tx),
   164→            handle,
   165→        };
   166→
   167→        self.inner
   168→            .server
   169→            .lock()
   170→            .map_err(|_| "server lock poisoned".to_string())?
   171→            .replace(running);
   172→
   173→        Ok(self.get_status())
   174→    }
   175→
   176→    /// Stop proxy server and return latest runtime status snapshot.
   177→    pub async fn stop(&self) -> Result<ProxyStatus, String> {
   178→        let running = self
   179→            .inner
   180→            .server
   181→            .lock()
   182→            .map_err(|_| "server lock poisoned".to_string())?
   183→            .take();
   184→
   185→        if let Some(mut srv) = running {
   186→            if let Some(tx) = srv.shutdown.take() {
   187→                let _ = tx.send(());
   188→            }
   189→            let _ =
   190→                tokio::time::timeout(std::time::Duration::from_millis(2500), &mut srv.handle).await;
   191→        }
   192→
   193→        self.inner.metrics.mark_stopped();
   194→
   195→        Ok(self.get_status())
   196→    }
   197→
   198→    /// Read lightweight runtime status including metrics and listen addresses.
   199→    pub fn get_status(&self) -> ProxyStatus {
   200→        let running_guard = self.inner.server.lock();
   201→        let (running, address, lan_address) = if let Ok(guard) = running_guard {
   202→            if let Some(srv) = guard.as_ref() {
   203→                (true, Some(srv.address.clone()), srv.lan_address.clone())
   204→            } else {
   205→                (false, None, None)
   206→            }
   207→        } else {
   208→            (false, None, None)
   209→        };
   210→
   211→        let metrics = self.inner.metrics.snapshot();
   212→
   213→        ProxyStatus {
   214→            running,
   215→            address,
   216→            lan_address,
   217→            metrics,
   218→        }
   219→    }
