    24→    /// Performs new.
    25→    pub fn new(file_path: PathBuf) -> Self {
    26→        let groups_db_path = file_path.with_file_name("providers.sqlite");
    27→        let groups_db = Connection::open(&groups_db_path).unwrap_or_else(|_| {
    28→            Connection::open_in_memory()
