    40→    /// Initializes data for this module's workflow.
    41→    pub fn initialize(&self) -> Result<(), String> {
    42→        if let Some(parent) = self.file_path.parent() {
    43→            std::fs::create_dir_all(parent)
    44→                .map_err(|e| format!("create config dir failed: {e}"))?;
    45→        }
    46→        if let Some(parent) = self.groups_db_path.parent() {
    47→            std::fs::create_dir_all(parent)
    48→                .map_err(|e| format!("create groups db dir failed: {e}"))?;
    49→        }
    50→        self.reopen_groups_db()?;
    51→        self.initialize_groups_db()?;
    52→
    53→        if !self.file_path.exists() {
    54→            let defaults = default_config();
    55→            self.save_groups_to_db(&defaults.groups)?;
    56→            self.write_file(&defaults)?;
    57→            self.set_in_memory(defaults);
    58→            return Ok(());
    59→        }
    60→
    61→        let raw = std::fs::read_to_string(&self.file_path)
    62→            .map_err(|e| format!("read config failed: {e}"))?;
    63→
    64→        let parsed = serde_json::from_str::<serde_json::Value>(&raw)
    65→            .unwrap_or_else(|_| serde_json::json!({}));
    66→        let migrated = migrate_config(parsed)?;
    67→        let mut normalized = normalize_config(migrated)?;
    68→        let groups_from_db = self.load_groups_from_db()?;
    69→        if groups_from_db.is_empty() {
    70→            self.save_groups_to_db(&normalized.groups)?;
    71→        } else {
    72→            normalized.groups = groups_from_db;
    73→        }
    74→
    75→        if let Err(err) = validate_config(&normalized) {
    76→            let defaults = default_config();
    77→            self.save_groups_to_db(&defaults.groups)?;
    78→            self.write_file(&defaults)?;
    79→            self.set_in_memory(defaults);
    80→            return Err(format!("config invalid, reset to default: {err}"));
    81→        }
    82→
    83→        self.write_file(&normalized)?;
    84→        self.set_in_memory(normalized);
    85→        Ok(())
    86→    }
