     0→//! Module Overview
     1→//! Config semantic validation rules.
     2→//! Ensures persisted and imported config data is internally consistent before runtime use.
     3→
     4→use crate::config::migrator::CURRENT_CONFIG_VERSION;
     5→use crate::domain::entities::ProxyConfig;
     6→
     7→/// Validates config for this module's workflow.
     8→pub fn validate_config(config: &ProxyConfig) -> Result<(), String> {
     9→    if config.config_version != CURRENT_CONFIG_VERSION {
    10→        return Err(format!("configVersion must be {CURRENT_CONFIG_VERSION}"));
    11→    }
    12→    if config.server.host.trim().is_empty() {
    13→        return Err("server.host must be non-empty".into());
    14→    }
    15→    if config.server.port == 0 {
    16→        return Err("server.port must be between 1 and 65535".into());
    17→    }
    18→    if config.server.auth_enabled && config.server.local_bearer_token.trim().is_empty() {
    19→        return Err("server.localBearerToken must be set when authEnabled=true".into());
    20→    }
    21→    if config.ui.theme != "light" && config.ui.theme != "dark" {
    22→        return Err("ui.theme must be light|dark".into());
    23→    }
    24→    if config.ui.locale != "en-US" && config.ui.locale != "zh-CN" {
    25→        return Err("ui.locale must be en-US|zh-CN".into());
    26→    }
    27→    if config.ui.locale_mode != "auto" && config.ui.locale_mode != "manual" {
    28→        return Err("ui.localeMode must be auto|manual".into());
    29→    }
    30→    if config.ui.quota_auto_refresh_minutes < 1 || config.ui.quota_auto_refresh_minutes > 1440 {
    31→        return Err("ui.quotaAutoRefreshMinutes must be between 1 and 1440".into());
    32→    }
    33→    if config.remote_git.branch.trim().is_empty() {
    34→        return Err("remoteGit.branch must be non-empty".into());
    35→    }
    36→
    37→    for group in &config.groups {
    38→        if group.id.trim().is_empty() {
    39→            return Err("group.id is required".into());
    40→        }
    41→        if !group
    42→            .id
    43→            .chars()
    44→            .all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-')
    45→        {
    46→            return Err(format!("group.id invalid: {}", group.id));
    47→        }
    48→        if group.name.trim().is_empty() {
    49→            return Err(format!("group.name is required for {}", group.id));
    50→        }
    51→        for provider in &group.providers {
    52→            if provider.id.trim().is_empty() {
    53→                return Err(format!("provider.id is required in group {}", group.id));
    54→            }
    55→            if provider.default_model.trim().is_empty() {
    56→                return Err(format!(
    57→                    "provider.defaultModel required for {}",
    58→                    provider.id
    59→                ));
    60→            }
    61→        }
    62→        if let Some(active) = &group.active_provider_id {
    63→            if !group.providers.iter().any(|r| r.id == *active) {
    64→                return Err(format!(
    65→                    "group.activeProviderId not found in providers for {}",
    66→                    group.id
    67→                ));
    68→            }
    69→        }
    70→    }
    71→
    72→    Ok(())
    73→}
